SELECT AVG(main) AS average_main_value
FROM safety_data
WHERE location = 'Lab A';

SELECT location
FROM safety_data
WHERE data_id = 0;

SELECT location
FROM safety_data
WHERE radi > 10.0;

SELECT AVG(calibration_value) AS average_calibration_value
FROM sensor_calibration
WHERE sensor_id = 0;

SELECT radi, location
FROM safety_data
WHERE radi = (SELECT MAX(radi) FROM safety_data);
